"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

/* --------------------------------- Context -------------------------------- */

interface StepperContextValue {
  activeStep: string
  orientation: "horizontal" | "vertical"
  onStepChange: (value: string) => void
  steps: string[]
  registerStep: (value: string) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("Stepper components must be used within a <Stepper />")
  }
  return context
}

interface StepperItemContextValue {
  value: string
  state: "active" | "completed" | "inactive"
  index: number
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItemContext() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error(
      "StepperItem sub-components must be used within a <StepperItem />"
    )
  }
  return context
}

/* --------------------------------- Stepper -------------------------------- */

function Stepper({
  value,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalStep, setInternalStep] = React.useState(defaultValue ?? "")
  const [steps, setSteps] = React.useState<string[]>([])

  const currentStep = value ?? internalStep

  const handleStepChange = React.useCallback(
    (newValue: string) => {
      if (value === undefined) {
        setInternalStep(newValue)
      }
      onValueChange?.(newValue)
    },
    [value, onValueChange]
  )

  const registerStep = React.useCallback((stepValue: string) => {
    setSteps((prev) =>
      prev.includes(stepValue) ? prev : [...prev, stepValue]
    )
  }, [])

  const contextValue = React.useMemo(
    () => ({
      activeStep: currentStep,
      orientation,
      onStepChange: handleStepChange,
      steps,
      registerStep,
    }),
    [currentStep, orientation, handleStepChange, steps, registerStep]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4 data-[orientation=horizontal]:flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

/* ------------------------------- StepperItem ------------------------------ */

function StepperItem({
  value,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { activeStep, steps, registerStep, orientation } = useStepperContext()

  React.useEffect(() => {
    registerStep(value)
  }, [registerStep, value])

  const activeIndex = steps.indexOf(activeStep)
  const itemIndex = steps.indexOf(value)
  const state: "active" | "completed" | "inactive" =
    itemIndex === activeIndex
      ? "active"
      : itemIndex < activeIndex
        ? "completed"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ value, state, index: itemIndex }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item relative flex items-center gap-3 data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

/* ----------------------------- StepperTrigger ----------------------------- */

function StepperTrigger({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepperContext()
  const { value, state, index } = useStepperItemContext()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      onClick={() => onStepChange(value)}
      className={cn(
        "flex items-center gap-3 rounded-md outline-none transition-colors focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      <span
        data-slot="stepper-indicator"
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
          state === "active" &&
            "border-primary bg-primary text-primary-foreground",
          state === "completed" &&
            "border-primary bg-primary text-primary-foreground",
          state === "inactive" &&
            "border-muted-foreground/40 text-muted-foreground"
        )}
      >
        {state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : (
          index + 1
        )}
      </span>
      {props.children && (
        <span data-slot="stepper-trigger-text" className="flex flex-col">
          {props.children}
        </span>
      )}
    </button>
  )
}

/* ------------------------------ StepperTitle ------------------------------ */

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItemContext()

  return (
    <span
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none",
        state === "active" && "text-foreground",
        state === "completed" && "text-foreground",
        state === "inactive" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

/* --------------------------- StepperDescription --------------------------- */

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItemContext()

  return (
    <span
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs text-muted-foreground",
        state === "inactive" && "text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}

/* ----------------------------- StepperSeparator ----------------------------- */

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "shrink-0 bg-muted-foreground/40 transition-colors data-[state=completed]:bg-primary data-[orientation=horizontal]:h-0.5 data-[orientation=vertical]:w-0.5 data-[orientation=horizontal]:flex-1 data-[orientation=vertical]:min-h-8 data-[orientation=vertical]:mx-auto",
        className
      )}
      {...props}
    />
  )
}

/* ----------------------------- StepperContent ----------------------------- */

function StepperContent({
  value,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { activeStep } = useStepperContext()

  if (activeStep !== value) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

